+            const stats = {
+                configured: true,
+                dimensions: parseInt(process.env.RUVBOT_EMBEDDING_DIM || '384', 10),
+                maxVectors: parseInt(process.env.RUVBOT_MAX_VECTORS || '100000', 10),
+                indexType: 'HNSW',
+                hnswM: parseInt(process.env.RUVBOT_HNSW_M || '16', 10),
