+`));
+        console.log(chalk_1.default.gray('Or use the REST API:'));
+        console.log(chalk_1.default.cyan(`
+  curl "http://localhost:3000/api/memory/search?q=${encodeURIComponent(options.query)}&limit=${options.limit}"
+`));
+    });
