+        .option('-y, --yes', 'Skip confirmation')
+        .action(async (options) => {
+        if (!options.yes) {
+            console.log(chalk_1.default.red('\n⚠ DANGER: This will clear ALL memory entries!'));
+            console.log(chalk_1.default.yellow('Use --yes flag to confirm'));
+            return;
